339	/**
340	 * Sync staged proposal files into brain.db.
341	 * Scans vault/studio/memory/*/staged/ directories.
342	 */
343	export async function syncStaged(opts?: { full?: boolean }): Promise<number> {
344	  const raw = getRawDb();
345	  let changed = 0;
346	
347	  if (opts?.full) {
348	    raw.exec("DELETE FROM staged_proposals");
349	    raw.exec("DELETE FROM sync_meta WHERE table_name = 'staged_proposals'");
350	  }
351	
352	  const currentPaths = new Set<string>();
353	
354	  // Scan all agent staged directories
355	  if (!existsSync(MEMORY_ROOT)) return 0;
356	  const agentDirs = readdirSync(MEMORY_ROOT, { withFileTypes: true })
357	    .filter(d => d.isDirectory() && d.name !== "raw");
358	
359	  for (const agentDir of agentDirs) {
360	    const stagedDir = join(MEMORY_ROOT, agentDir.name, "staged");
361	    if (!existsSync(stagedDir)) continue;
362	
363	    const files = findMdFiles(stagedDir);
364	    for (const filePath of files) {
365	      const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
366	      currentPaths.add(sourcePath);
367	
368	      const rawContent = readFileSync(filePath, "utf-8");
369	      const hash = hashFile(rawContent);
370	
371	      // Check if already synced
372	      const db = getDb();
373	      const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
374	      if (existing && existing.fileHash === hash && !opts?.full) continue;
375	
376	      // Parse frontmatter
377	      const parsed = parseFile(filePath);
378	      const fm = parsed.frontmatter;
379	      const ts = now();
380	
381	      raw.exec(`
382	        INSERT INTO staged_proposals (agent, section, change_type, proposed_change, reason, status, source_path, file_hash, created_at, updated_at)
383	        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
384	        ON CONFLICT(source_path) DO UPDATE SET
385	          agent=excluded.agent, section=excluded.section, change_type=excluded.change_type,
386	          proposed_change=excluded.proposed_change, reason=excluded.reason,
387	          status=excluded.status, file_hash=excluded.file_hash, updated_at=excluded.updated_at
388	      `.trim(), [
389	        fm.agent ?? agentDir.name,
390	        fm.section ?? "",
391	        fm.change_type ?? "add",
392	        parsed.body.slice(0, 2000),  // truncate for DB
393	        fm.reason ?? "",
394	        fm.status ?? "pending",
395	        sourcePath, hash, ts, ts,
396	      ] as any);
397	
398	      // Upsert sync meta
399	      raw.exec(`
400	        INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
401	        VALUES (?, ?, 'staged_proposals', ?)
402	        ON CONFLICT(source_path) DO UPDATE SET
403	          file_hash=excluded.file_hash, synced_at=excluded.synced_at
404	      `.trim(), [sourcePath, hash, ts] as any);
405	
406	      changed++;
407	    }
408	  }
409	
410	  // Remove orphans
411	  const allRows = raw.prepare("SELECT source_path FROM staged_proposals").all() as { source_path: string }[];
412	  for (const row of allRows) {
413	    if (!currentPaths.has(row.source_path)) {
414	      raw.exec("DELETE FROM staged_proposals WHERE source_path = ?", [row.source_path] as any);
415	      raw.exec("DELETE FROM sync_meta WHERE source_path = ?", [row.source_path] as any);
416	    }
417	  }
418	
419	  return changed;
420	}
421	```
