430	/** Full-text search across staged proposals. */
431	export function searchStaged(query: string, opts?: { agent?: string; status?: string; limit?: number }): Array<{
432	  id: number; agent: string; section: string; changeType: string;
433	  proposedChange: string; reason: string; status: string;
434	  sourcePath: string; rank: number;
435	}> {
436	  const raw = getRawDb();
437	  const limit = opts?.limit ?? 20;
438	  const safeQuery = sanitizeFtsQuery(query);
439	
440	  let sql = `
441	    SELECT s.id, s.agent, s.section, s.change_type, s.proposed_change,
442	           s.reason, s.status, s.source_path, rank
443	    FROM staged_fts
444	    JOIN staged_proposals s ON s.id = staged_fts.rowid
445	    WHERE staged_fts MATCH ?
446	  `;
447	  const params: any[] = [safeQuery];
448	
449	  if (opts?.agent) {
450	    sql += " AND s.agent = ?";
451	    params.push(opts.agent);
452	  }
453	  if (opts?.status) {
454	    sql += " AND s.status = ?";
455	    params.push(opts.status);
456	  }
457	
458	  sql += " ORDER BY rank LIMIT ?";
459	  params.push(limit);
460	
461	  const rows = raw.prepare(sql).all(...params) as any[];
462	  return rows.map(r => ({
463	    id: r.id,
464	    agent: r.agent,
465	    section: r.section,
466	    changeType: r.change_type,
467	    proposedChange: r.proposed_change,
468	    reason: r.reason,
469	    status: r.status,
470	    sourcePath: r.source_path,
471	    rank: r.rank,
472	  }));
473	}
