/**
 * brain/index.ts — Brain module barrel export + init
 *
 * Call initBrain() once at startup to ensure tables and FTS
 * indexes exist. All other imports are re-exported from here.
 */

import { getDb, getRawDb, closeDb } from "../sqlite.js";
import { initFts } from "./fts.js";
import { sql } from "drizzle-orm";
import * as sqliteVec from "sqlite-vec";

// Re-export everything consumers need
export * from "./schema.js";
export * from "./queries.js";
export * from "./sync.js";
export * from "./raw.js";
export { initFts, rebuildFts } from "./fts.js";
export { chunkMarkdown } from "./chunker.js";
export { getProfile, rerankResults, type BoostProfile } from "./reranker.js";
export { knowledgeStaleness, decayedConfidence, isEmbeddingStale, currentEmbedModel } from "./degradation.js";
// raw.ts exports covered by wildcard on line 17

let _initialized = false;

/**
 * Initialize brain.db — create Drizzle tables and FTS5 indexes.
 * Idempotent: safe to call multiple times.
 */
export function initBrain(): void {
  if (_initialized) return;

  const raw = getRawDb();

  // Create base tables via raw SQL (Drizzle push needs drizzle-kit CLI).
  // These match the Drizzle schema exactly.
  raw.exec(`
    CREATE TABLE IF NOT EXISTS memories (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      agent TEXT NOT NULL,
      tier TEXT NOT NULL,
      title TEXT NOT NULL,
      content TEXT NOT NULL,
      tags TEXT,
      memory_type TEXT,
      source_path TEXT NOT NULL UNIQUE,
      file_hash TEXT NOT NULL,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);

  raw.exec(`
    CREATE TABLE IF NOT EXISTS 'references' (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      collection TEXT NOT NULL,
      title TEXT NOT NULL,
      content TEXT NOT NULL,
      tags TEXT,
      frontmatter TEXT,
      source_path TEXT NOT NULL UNIQUE,
      file_hash TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);

  raw.exec(`
    CREATE TABLE IF NOT EXISTS decisions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      agent TEXT NOT NULL,
      decision TEXT NOT NULL,
      context TEXT NOT NULL,
      alternatives TEXT,
      outcome TEXT,
      confidence REAL DEFAULT 0.5,
      tags TEXT,
      project TEXT DEFAULT 'unknown',
      project_path TEXT,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);

  raw.exec(`
    CREATE TABLE IF NOT EXISTS sync_meta (
      source_path TEXT PRIMARY KEY,
      file_hash TEXT NOT NULL,
      table_name TEXT NOT NULL,
      synced_at TEXT NOT NULL
    );
  `);

  raw.exec(`
    CREATE TABLE IF NOT EXISTS entities (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL UNIQUE,
      type TEXT NOT NULL,
      summary TEXT,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);

  raw.exec(`
    CREATE TABLE IF NOT EXISTS entity_relations (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      source_id INTEGER NOT NULL,
      target_id INTEGER NOT NULL,
      relation TEXT NOT NULL,
      weight REAL DEFAULT 1.0,
      evidence TEXT,
      created_at TEXT NOT NULL
    );
  `);

  // Reference chunks table
  raw.exec(`
    CREATE TABLE IF NOT EXISTS reference_chunks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      reference_id INTEGER NOT NULL,
      collection TEXT NOT NULL,
      source_path TEXT NOT NULL,
      section_name TEXT NOT NULL,
      content TEXT NOT NULL,
      line_start INTEGER NOT NULL,
      line_end INTEGER NOT NULL,
      tags TEXT,
      token_count INTEGER,
      embedding TEXT,
      file_hash TEXT NOT NULL,
      embed_model TEXT,
      embedded_at TEXT,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);
  raw.exec("CREATE INDEX IF NOT EXISTS idx_chunks_collection ON reference_chunks(collection)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_chunks_source ON reference_chunks(source_path)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_chunks_hash ON reference_chunks(file_hash)");

  // Project chunks table
  raw.exec(`
    CREATE TABLE IF NOT EXISTS project_chunks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      project TEXT NOT NULL,
      doc_type TEXT NOT NULL,
      source_path TEXT NOT NULL,
      section_name TEXT NOT NULL,
      content TEXT NOT NULL,
      line_start INTEGER NOT NULL,
      line_end INTEGER NOT NULL,
      tags TEXT,
      status TEXT,
      token_count INTEGER,
      embedding TEXT,
      file_hash TEXT NOT NULL,
      embed_model TEXT,
      embedded_at TEXT,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);
  raw.exec("CREATE INDEX IF NOT EXISTS idx_proj_chunks_project ON project_chunks(project)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_proj_chunks_source ON project_chunks(source_path)");

  // Raw files table (eidetic context — not agent memory)
  raw.exec(`
    CREATE TABLE IF NOT EXISTS raw_files (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      ts INTEGER NOT NULL UNIQUE,
      date TEXT NOT NULL,
      agents TEXT NOT NULL,
      skill TEXT,
      tags TEXT,
      summary TEXT,
      source_path TEXT NOT NULL UNIQUE,
      file_hash TEXT NOT NULL,
      created_at TEXT NOT NULL
    );
  `);
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_files_ts ON raw_files(ts)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_files_skill ON raw_files(skill)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_files_date ON raw_files(date)");

  // Raw chunks table
  raw.exec(`
    CREATE TABLE IF NOT EXISTS raw_chunks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      raw_id INTEGER NOT NULL,
      section_name TEXT NOT NULL,
      content TEXT NOT NULL,
      line_start INTEGER NOT NULL,
      line_end INTEGER NOT NULL,
      token_count INTEGER,
      embedding TEXT,
      file_hash TEXT NOT NULL,
      embed_model TEXT,
      embedded_at TEXT,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
  `);
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_chunks_raw_id ON raw_chunks(raw_id)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_chunks_source ON raw_chunks(file_hash)");

  // Raw tool calls table (JSONL-sourced, per-tool-call index)
  raw.exec(`
    CREATE TABLE IF NOT EXISTS raw_tool_calls (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      raw_id INTEGER NOT NULL,
      tool_name TEXT NOT NULL,
      tool_use_id TEXT,
      input_summary TEXT,
      line_number INTEGER,
      created_at TEXT NOT NULL
    );
  `);
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_tool_calls_tool ON raw_tool_calls(tool_name)");
  raw.exec("CREATE INDEX IF NOT EXISTS idx_raw_tool_calls_raw_id ON raw_tool_calls(raw_id)");

  // Migrations — add columns to existing tables
  try { raw.exec("ALTER TABLE memories ADD COLUMN memory_type TEXT"); } catch {}
  try { raw.exec("ALTER TABLE memories ADD COLUMN embedding TEXT"); } catch {}
  try { raw.exec("ALTER TABLE decisions ADD COLUMN project TEXT DEFAULT 'unknown'"); } catch {}
  try { raw.exec("ALTER TABLE decisions ADD COLUMN project_path TEXT"); } catch {}
  try { raw.exec("ALTER TABLE decisions ADD COLUMN embedding TEXT"); } catch {}
  try { raw.exec("ALTER TABLE memories ADD COLUMN embed_model TEXT"); } catch {}
  try { raw.exec("ALTER TABLE memories ADD COLUMN last_reinforced_at TEXT"); } catch {}
  try { raw.exec("ALTER TABLE memories ADD COLUMN embedded_at TEXT"); } catch {}
  try { raw.exec("ALTER TABLE decisions ADD COLUMN embed_model TEXT"); } catch {}
  try { raw.exec("ALTER TABLE decisions ADD COLUMN embedded_at TEXT"); } catch {}
  try { raw.exec("ALTER TABLE decisions ADD COLUMN raw_ref INTEGER"); } catch {}
  // Raw files schema evolution — JSONL support
  try { raw.exec("ALTER TABLE raw_files ADD COLUMN session_id TEXT"); } catch {}
  try { raw.exec("ALTER TABLE raw_files ADD COLUMN format TEXT DEFAULT 'json'"); } catch {}
