/** Build aggregate summary of a pipeline run. */
function buildPipelineSummary(
  results: AgentDistillResult[],
  durationMs: number,
): PipelineSummary {
  let totalProposals = 0;
  let autoApplied = 0;
  let staged = 0;
  let errors = 0;
