        lines.push(`    Failed gates: ${p.gateResults.failedGates.join(", ")}`);
      }
      if (p.judgeResults && p.judgeResults.dissents.length > 0) {
        lines.push(`    Dissents: ${p.judgeResults.dissents.join(", ")}`);
      }
    }
    lines.push("");
  }

  writeFileSync(filePath, lines.join("\n"), "utf-8");
  return filePath;
}
