  lines.push(`  Staged: ${s.staged}`);
  lines.push(`  Skipped agents: ${s.skippedAgents}`);
  if (s.errors > 0) lines.push(`  Errors: ${s.errors}`);
  lines.push("");

  for (const agent of result.agents) {
